#include <stdio.h>
#include <stdbool.h>
#include <string.h>
#define MAX_SIZE 1001
char a[MAX_SIZE];
int top = -1;
void push(char ele){
    if(top <= MAX_SIZE - 2){
        a[++top] = ele;
    }
    else{
        printf("Stack is full. Cannot push: %c\n", ele);
    }
}
char pop(){
    if(top >= 0){
        char ele = a[top];
        top--;
        return ele;
    }
    else{
        printf("Stack is empty. Cannot pop.\n");
        return '\0';
    }
}
bool isEmpty(){
    return top == -1;
}
bool isFull(){
    return top >= MAX_SIZE - 1;
}
bool isMatchingPair(char open, char close) {
    return (open == '(' && close == ')');
}
bool isBalanced(char expression[]) {
    int length = strlen(expression);
    for (int i = 0; i < length; i++){
        char c = expression[i];
        if (c == '(') {
            push(c);
        } 
        else if (c == ')'){
            if (isEmpty()){
                return false;
            }
            char topChar = pop();
            if (!isMatchingPair(topChar, c)) {
                return false;
            }
        }
    }
    return isEmpty(); 
}
int main(){
    int t;
    scanf("%d", &t);
    while(t--){
        char str[MAX_SIZE];
        scanf("%s", str);
        printf("%s : ", str);
        bool ans = isBalanced(str);
        if(ans)
            printf("true\n");
        else
            printf("false\n");
    }
    return 0;
}

