import java.util.Scanner;
public class Main {
    static final int MAX_SIZE = 1001;
    static char[] a = new char[MAX_SIZE];
    static int top = -1;
    public static void push(char ele) {
        if (top <= MAX_SIZE - 2) {
            a[++top] = ele;
        } else {
            System.out.println("Stack is full. Cannot push: " + ele);
        }
    }
    public static char pop() {
        if (top >= 0) {
            char ele = a[top];
            top--;
            return ele;
        } else {
            System.out.println("Stack is empty. Cannot pop.");
            return '\0';
        }
    }
    public static boolean isEmpty() {
        return top == -1;
    }
    public static boolean isFull() {
        return top >= MAX_SIZE - 1;
    }
    public static boolean isMatchingPair(char open, char close) {
        return (open == '(' && close == ')');
    }
    public static boolean isBalanced(String expression) {
        for (int i = 0; i < expression.length(); i++) {
            char c = expression.charAt(i);
            if (c == '(') {
                push(c);
            } else if (c == ')'){
                if (isEmpty()){
                    return false;
                }
                char topChar = pop();
                if (!isMatchingPair(topChar, c)) {
                    return false;
                }
            }
        }
        return isEmpty(); 
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        scanner.nextLine();
        while (t-- > 0) {
            String str = scanner.nextLine();
            System.out.println(str + " : " + isBalanced(str));
        }
    }
}

